{
  "global": "Implement `numerical_letter_grade` by iterating over each GPA and classifying it via ordered threshold comparisons that map to one of 13 letter grades.",
  "subtasks": [
    {
      "subtask": "Encode the complete GPA-to-letter-grade mapping as ordered threshold conditions",
      "atomics": [
        "List all 13 grade bands in descending GPA order: 4.0==A+, >3.7=A, >3.3=A-, >3.0=B+, >2.7=B, >2.3=B-, >2.0=C+, >1.7=C, >1.3=C-, >1.0=D+, >0.7=D, >0.0=D-, else E",
        "Identify the two exact-equality edge cases: GPA==4.0 must be checked before the >3.7 condition, and GPA==0.0 falls through all '>' checks to the else branch"
      ]
    },
    {
      "subtask": "Implement per-GPA classification logic using an if/elif/else chain",
      "atomics": [
        "Open with `if gpa == 4.0: letter = 'A+'` to avoid the 4.0 edge case being caught by a strict-greater comparison",
        "Add `elif gpa > 3.7`, `elif gpa > 3.3`, … `elif gpa > 0.0` branches in descending order, each assigning the corresponding letter string",
        "Close with `else: letter = 'E'` to handle the GPA==0.0 case"
      ]
    },
    {
      "subtask": "Collect results into the output list and return",
      "atomics": [
        "Wrap the classification logic in a list comprehension `[classify(gpa) for gpa in grades]` or an equivalent for-loop with `result.append(...)`",
        "Return the assembled list of letter grade strings"
      ]
    }
  ],
  "global_atomics": [
    "Trace the provided example: 4.0->A+, 3.0->B (3.0 not >3.0, but >2.7), 1.7->C- (1.7 not >1.7, but >1.3), 2.0->C (2.0 not >2.0, but >1.7), 3.5->A- (3.5>3.3) and confirm the output equals ['A+', 'B', 'C-', 'C', 'A-']"
  ],
  "gold_actions": {
    "global": "Iterate over the `grades` list with a list comprehension, classifying each float GPA through a 13-branch if/elif/else chain and returning the resulting letter-grade list.",
    "subtasks": [
      {
        "subtask": "Write the 13 threshold constants and their grade labels in source order",
        "atomics": [
          "Express the mapping as code-ready conditions: `gpa==4.0:'A+'`, `gpa>3.7:'A'`, `gpa>3.3:'A-'`, `gpa>3.0:'B+'`, `gpa>2.7:'B'`, `gpa>2.3:'B-'`, `gpa>2.0:'C+'`, `gpa>1.7:'C'`, `gpa>1.3:'C-'`, `gpa>1.0:'D+'`, `gpa>0.7:'D'`, `gpa>0.0:'D-'`, `else:'E'`",
          "Confirm that placing `gpa==4.0` first prevents 4.0 from incorrectly matching `gpa>3.7`"
        ]
      },
      {
        "subtask": "Implement the if/elif/else classification block for a single GPA value",
        "atomics": [
          "Write `if gpa == 4.0: return 'A+'` as the first branch inside a helper function or inline lambda",
          "Chain 11 `elif gpa > threshold: return grade` statements in strictly descending threshold order",
          "Add `else: return 'E'` as the final branch to handle GPA==0.0"
        ]
      },
      {
        "subtask": "Build and return the output list",
        "atomics": [
          "Use `return [<classification_block>(gpa) for gpa in grades]` where the classification block is either an inline conditional expression or a call to a named helper",
          "Ensure the list preserves input order so index i of output corresponds to index i of grades"
        ]
      }
    ],
    "global_atomics": [
      "Manually evaluate `numerical_letter_grade([4.0, 3, 1.7, 2, 3.5])` step-by-step against the if/elif chain to verify it returns `['A+', 'B', 'C-', 'C', 'A-']` before finalising the implementation"
    ]
  }
}
